#include <bits/stdc++.h>
using namespace std;

int n;
pair<int, int> c[100005];
int a[100005];
int f[100005];

bool cmp(pair<int, int> a, pair<int, int> b) {
    if (a.first == b.first) return a.second < b.second;
    return a.first < b.first;
}

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> c[i].first >> c[i].second;
        f[i] = INT_MAX;
    }
    sort(c, c + n, cmp);
    for (int i = 0; i < n; i++) {
        a[i] = c[i].second - c[i].first;
    }
    for (int i = 0; i < n; i++) {
        if (a[i] < 0) continue;
        *upper_bound(f, f + n, a[i]) = a[i];
    }
    cout << lower_bound(f, f + n, INT_MAX) - f;
    return 0;
}
